#include<bits/stdc++.h>
#define ls (x<<1)
#define rs (x<<1|1)
using namespace std;
int n,m,op,l,r,k,v;
struct segment_tree
{
    long long sum;
    int l,r,maxa,cnt,se,maxb;
    int add1,add2,add3,add4;
}s[2000010];
void pushup(int x)
{
    s[x].sum=s[ls].sum+s[rs].sum;
    s[x].maxa=max(s[ls].maxa,s[rs].maxa);
    s[x].maxb=max(s[ls].maxb,s[rs].maxb);
    if(s[ls].maxa==s[rs].maxa)
    {
        s[x].se=max(s[ls].se,s[rs].se);
        s[x].cnt=s[ls].cnt+s[rs].cnt;
    }
    else if(s[ls].maxa>s[rs].maxa)
    {
        s[x].se=max(s[ls].se,s[rs].maxa);
        s[x].cnt=s[ls].cnt;
    }
    else
    {
        s[x].se=max(s[ls].maxa,s[rs].se);
        s[x].cnt=s[rs].cnt;
    }
}
void build(int l,int r,int x)
{
    s[x].l=l;
    s[x].r=r;
    if(l==r)
    {
        int val;
        scanf("%d",&val);
        s[x].sum=s[x].maxa=s[x].maxb=val;
        s[x].cnt=1;
        s[x].se=-2e9;
        return;
    }
    int mid=(l+r)>>1;
    build(l,mid,ls);
    build(mid+1,r,rs);
    pushup(x);
}
void change(int k1,int k2,int k3,int k4,int x)
{
    s[x].sum+=1ll*k1*s[x].cnt+1ll*k2*(s[x].r-s[x].l+1-s[x].cnt);
    s[x].maxb=max(s[x].maxb,s[x].maxa+k3);
    s[x].maxa+=k1;
    if(s[x].se!=-2e9)
    {
        s[x].se+=k2;
    }
    s[x].add3=max(s[x].add3,s[x].add1+k3);
    s[x].add4=max(s[x].add4,s[x].add2+k4);
    s[x].add1+=k1;
    s[x].add2+=k2;
}
void pushdown(int x)
{
    int maxn=max(s[ls].maxa,s[rs].maxa);
    if(s[ls].maxa==maxn)
    {
        change(s[x].add1,s[x].add2,s[x].add3,s[x].add4,ls);
    }
    else
    {
        change(s[x].add2,s[x].add2,s[x].add4,s[x].add4,ls);
    }
    if(s[rs].maxa==maxn)
    {
        change(s[x].add1,s[x].add2,s[x].add3,s[x].add4,rs);
    }
    else
    {
        change(s[x].add2,s[x].add2,s[x].add4,s[x].add4,rs);
    }
    s[x].add1=s[x].add2=s[x].add3=s[x].add4=0;
}
void update_add(int x)
{
    if(l>s[x].r||r<s[x].l)
    {
        return;
    }
    if(l<=s[x].l&&s[x].r<=r)
    {
        s[x].sum+=1ll*k*s[x].cnt+1ll*k*(s[x].r-s[x].l+1-s[x].cnt);
        s[x].maxa+=k;
        s[x].maxb=max(s[x].maxb,s[x].maxa);
        if(s[x].se!=-2e9)
        {
            s[x].se+=k;
        }
        s[x].add1+=k;
        s[x].add2+=k;
        s[x].add3=max(s[x].add3,s[x].add1);
        s[x].add4=max(s[x].add4,s[x].add2);
        return;
    }
    pushdown(x);
    update_add(ls);
    update_add(rs);
    pushup(x);
}
void update_min(int x)
{
    if(l>s[x].r||r<s[x].l||v>=s[x].maxa)
    {
        return;
    }
    if(l<=s[x].l&&s[x].r<=r&&s[x].se<v)
    {
        int k=s[x].maxa-v;
        s[x].sum-=1ll*s[x].cnt*k;
        s[x].maxa=v;
        s[x].add1-=k;
        return;
    }
    pushdown(x);
    update_min(ls);
    update_min(rs);
    pushup(x);
}
long long query_sum(int x)
{
    if(l>s[x].r||r<s[x].l)
    {
        return 0;
    }
    if(l<=s[x].l&&s[x].r<=r)
    {
        return s[x].sum;
    }
    pushdown(x);
    return query_sum(ls)+query_sum(rs);
}
long long query_maxa(int x)
{
    if(l>s[x].r||r<s[x].l)
    {
        return -2e9;
    }
    if(l<=s[x].l&&s[x].r<=r)
    {
        return s[x].maxa;
    }
    pushdown(x);
    return max(query_maxa(ls),query_maxa(rs));
}
long long query_maxb(int x)
{
    if(l>s[x].r||r<s[x].l)
    {
        return -2e9;
    }
    if(l<=s[x].l&&s[x].r<=r)
    {
        return s[x].maxb;
    }
    pushdown(x);
    return max(query_maxb(ls),query_maxb(rs));
}
int main()
{
    scanf("%d%d",&n,&m);
    build(1,n,1);
    while(m--)
    {
        scanf("%d%d%d",&op,&l,&r);
        if(op==1)
        {
            scanf("%d",&k);
            update_add(1);
        }
        else if(op==2)
        {
            scanf("%d",&v);
            update_min(1);
        }
        else if(op==3)
        {
            printf("%lld\n",query_sum(1));
        }
        else if(op==4)
        {
            printf("%d\n",query_maxa(1));
        }
        else
        {
            printf("%d\n",query_maxb(1));
        }
    }
    return 0;
}
